def on_tick_timer1():
    if globals().get('game_over'):
        if not globals().get('__msg__'):
            import sys
            sys.exit(0)
        return
    time_txt.caption = str(int(time_txt.caption) + 1)

bombs = {(2,1),(3,8),(4,0),(5,1),(5,7),(7,1),(8,2),(9,2),(9,3),(9,9)}

def get_adj(r, c):
    return sum(1 for dr in [-1,0,1] for dc in [-1,0,1] if (r+dr, c+dc) in bombs)

def click_cell(r, c):
    btn = globals()[f'b{r}_{c}']
    if btn.caption not in ['', 'F']: return
    if (r, c) in bombs:
        face_txt.caption = "(T_T)"
        btn.caption = "*"
        btn.bg_color = 15
        msgbox("game over")
        globals()['game_over'] = True
    else:
        face_txt.caption = "(^_^)"
        q = [(r, c)]
        while q:
            curr_r, curr_c = q.pop(0)
            c_btn = globals().get(f'b{curr_r}_{curr_c}')
            if not c_btn or c_btn.caption not in ['', 'F']: continue
            c_bombs = get_adj(curr_r, curr_c)
            if c_bombs > 0:
                c_btn.caption = str(c_bombs)
            else:
                c_btn.caption = "-"
                for dr in [-1, 0, 1]:
                    for dc in [-1, 0, 1]:
                        if dr == 0 and dc == 0: continue
                        nr, nc = curr_r + dr, curr_c + dc
                        if 0 <= nr <= 9 and 0 <= nc <= 9:
                            n_btn = globals().get(f'b{nr}_{nc}')
                            if n_btn and n_btn.caption == "":
                                q.append((nr, nc))

